eql.source:
update LitemallOrder
set orderStatus = ${newStatus}
where id = ${orderId} and orderStatus = ${expectedStatus}

sql.source:
SELECT PAY_TIME AS PAY_TIME, ACTUAL_PRICE AS ACTUAL_PRICE
FROM litemall_order
WHERE CAST(DELETED AS INT) = 0
  AND CAST(ORDER_STATUS AS INT) >= 201
  AND PAY_TIME >= ${startDate}
  AND PAY_TIME <= ${endDate}
